"""Minimal JSON Schema validator."""
from typing import Any, Dict, List

TYPE_MAP = {
    "string": str,
    "number": (int, float),
    "integer": int,
    "boolean": bool,
    "object": dict,
    "array": list,
}


class ValidationError:
    def __init__(self, path: str, message: str):
        self.path = path
        self.message = message

    def __repr__(self):
        return f"ValidationError({self.path}: {self.message})"


def validate(schema: Dict, data: Any, path: str = "$") -> List[ValidationError]:
    """Validate data against a JSON schema. Returns list of errors."""
    errors: List[ValidationError] = []

    # Type check
    if "type" in schema:
        expected = TYPE_MAP.get(schema["type"])
        if expected and not isinstance(data, expected):
            errors.append(ValidationError(path, f"expected type {schema['type']}"))
            return errors  # Skip further checks if type is wrong

    # Required fields (for objects)
    if "required" in schema and isinstance(data, dict):
        for field in schema["required"]:
            if field not in data:
                errors.append(ValidationError(f"{path}.{field}", "is required"))

    # String constraints
    if "minLength" in schema and isinstance(data, str):
        if len(data) < schema["minLength"]:
            errors.append(ValidationError(
                path, f"must be at least {schema['minLength']} characters"
            ))

    # Number constraints
    if "maximum" in schema and isinstance(data, (int, float)):
        if data > schema["maximum"]:
            errors.append(ValidationError(
                path, f"must be at most {schema['maximum']}"
            ))

    # Recurse into properties
    if "properties" in schema and isinstance(data, dict):
        for prop, prop_schema in schema["properties"].items():
            if prop in data:
                errors.extend(validate(prop_schema, data[prop], f"{path}.{prop}"))

    return errors
